// Mode: Run Once for All Items
const items = $input.all();
return items.map((item) => {
  const e = item.json || {};

  let fotos = [];
  try {
    fotos = typeof e.fotos === "string" ? JSON.parse(e.fotos) : (e.fotos || []);
  } catch (err) {
    fotos = [];
  }
  if (!Array.isArray(fotos)) fotos = [];

  const fotosOrdenadas = [...fotos].sort((a, b) => {
    const na = (a && typeof a.nota_capa === "number") ? a.nota_capa : -Infinity;
    const nb = (b && typeof b.nota_capa === "number") ? b.nota_capa : -Infinity;

    // Primeiro: nota decrescente
    if (nb !== na) return nb - na;

    // Desempate: foto_index crescente (menor index primeiro)
    const ia = (a && typeof a.foto_index === "number") ? a.foto_index : Infinity;
    const ib = (b && typeof b.foto_index === "number") ? b.foto_index : Infinity;
    return ia - ib;
  });

  return {
    json: {
      ...e,
      fotos: fotosOrdenadas,
    },
  };
});

// Mode: Run Once for All Items

const SUPABASE_URL = "https://veedrfffsquvyypjrquh.supabase.co";
const BUCKET = "TRIP";
const KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZlZWRyZmZmc3F1dnl5cGpycXVoIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3ODg2OTQyMSwiZXhwIjoyMDk0NDQ1NDIxfQ.0Z341oGGbmFl2ce8TLVTs55F2667wdug0aF1iFNSNVw";

const MAX_RETRIES = 3;
const RETRY_DELAY_MS = 1500;

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const extPorContentType = (ct) => {
  if (!ct) return "jpg";
  if (ct.includes("png")) return "png";
  if (ct.includes("webp")) return "webp";
  if (ct.includes("gif")) return "gif";
  return "jpg";
};

const items = $input.all();
const contadorPorId = {};
const resultados = [];

for (const item of items) {
  const e = item.json || {};

  let url = e.url || e.url_original;
  const id = e.id || "sem_id";

  if (!url) continue;

  // Tenta obter uma versão de boa qualidade sem ficar pesada
  if (url.includes("googleusercontent.com")) {
    url = url.replace(
      /=w\d+-h\d+.*$/i,
      "=w1600-h1600-k-no"
    );
  }

  const idx = contadorPorId[id] ?? 0;
  contadorPorId[id] = idx + 1;

  // 1. Download da imagem
  let img = null;
  let lastErr = null;

  for (let tentativa = 1; tentativa <= MAX_RETRIES; tentativa++) {
    try {
      img = await this.helpers.httpRequest({
        method: "GET",
        url,
        encoding: "arraybuffer",
        returnFullResponse: true,
        timeout: 20000,
        headers: {
          "User-Agent":
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
          Accept: "image/webp,image/apng,image/*,*/*;q=0.8",
        },
      });

      break;
    } catch (err) {
      lastErr = err;

      const status =
        err.response?.statusCode || err.statusCode;

      if (status === 403 || status === 404) {
        break;
      }

      if (tentativa < MAX_RETRIES) {
        await sleep(RETRY_DELAY_MS * tentativa);
      }
    }
  }

  if (!img || !img.body || img.body.length === 0) {
    const status =
      lastErr?.response?.statusCode ||
      lastErr?.statusCode ||
      "vazio";

    resultados.push({
      json: {
        id,
        foto_index: idx,
        url,
        sucesso: false,
        erro: `download_falhou_${status}`,
      },
    });

    continue;
  }

  const contentType =
    img.headers["content-type"] || "image/jpeg";

  const ext = extPorContentType(contentType);

  const path = `${id}/${idx}.${ext}`;

  // 2. Upload para Supabase Storage
  let uploadOk = false;
  let uploadErr = null;

  for (let tentativa = 1; tentativa <= MAX_RETRIES; tentativa++) {
    try {
      await this.helpers.httpRequest({
        method: "POST",
        url: `${SUPABASE_URL}/storage/v1/object/${BUCKET}/${path}`,
        timeout: 30000,
        headers: {
          Authorization: `Bearer ${KEY}`,
          "Content-Type": contentType,
          "x-upsert": "true",
        },
        body: Buffer.from(img.body),
      });

      uploadOk = true;
      break;
    } catch (err) {
      uploadErr = err;

      if (tentativa < MAX_RETRIES) {
        await sleep(RETRY_DELAY_MS * tentativa);
      }
    }
  }

  if (!uploadOk) {
    resultados.push({
      json: {
        id,
        foto_index: idx,
        url,
        path,
        sucesso: false,
        erro:
          "upload_falhou: " +
          JSON.stringify(
            uploadErr?.response?.body ??
              uploadErr?.response?.data ??
              uploadErr?.message
          ),
      },
    });

    continue;
  }

  resultados.push({
    json: {
      id,
      foto_index: idx,
      path,
      sucesso: true,
      public_url: `${SUPABASE_URL}/storage/v1/object/public/${BUCKET}/${path}`,
    },
  });
}

return resultados;

// Mode: Run Once for All Items
// Agrupa as imagens por estabelecimento (id), montando uma lista de URLs por id.

const items = $input.all();
const porId = {};

for (const item of items) {
  const e = item.json || {};
  const id = e.id;
  if (!id) continue;

  if (!porId[id]) {
    porId[id] = {
      id,
      qtd_fotos: 0,
      capa: null,
      _temp: [],   // guarda index+url para ordenar depois
    };
  }

  porId[id]._temp.push({ foto_index: e.foto_index, url: e.public_url });

  if (e.foto_index === 0) {
    porId[id].capa = e.public_url;
  }
}

return Object.values(porId).map((grupo) => {
  // ordena por foto_index e extrai só a URL
  grupo._temp.sort((a, b) => a.foto_index - b.foto_index);
  const fotos = grupo._temp.map((f) => f.url);
  delete grupo._temp;

  return {
    json: {
      id: grupo.id,
      qtd_fotos: fotos.length,
      capa: grupo.capa,
      fotos, // array só com as URLs, em ordem
    },
  };
});

const items = $input.all().map(i => i.json);

// Separa uploads de estabelecimentos
const uploads = {};
const estabelecimentos = {};

for (const item of items) {
  const id = item.id;
  if (!id) continue;

  // É um item de upload se tiver capa e não tiver nome
  if (item.capa && !item.nome) {
    uploads[id] = item;
  } else if (item.nome) {
    estabelecimentos[id] = item;
  }
}

// Mescla upload + estabelecimento pelo id
return Object.keys(estabelecimentos).map(id => {
  const est = estabelecimentos[id];
  const upload = uploads[id] || {};

  return {
    json: {
      ...est,
      capa: upload.capa ?? null,
      fotos_salvas: upload.fotos ?? [],
      qtd_fotos_salvas: upload.qtd_fotos ?? 0,
    }
  };
});

// Mode: Run Once for All Items
// Gera UMA row por foto (para o Switch funcionar), sem duplicatas e COM O ID do restaurante.
const categoriasInuteis = ["Street View & 360°", "Videos", "Menu"];
const rows = [];
// 1. Pega TODOS os restaurantes que entraram no nó
const items = $input.all();
for (const item of items) {
  const e = item.json || {};
  const idEstabelecimento = e.id || null;
  const fotos = Array.isArray(e.fotos) ? e.fotos : [];
  const urlsProcessadas = new Set();
  // 2. Transforma cada foto em um item isolado
  for (let i = 0; i < fotos.length; i++) {
    const foto = fotos[i] || {};
    const url = foto.url || "";
    const description = foto.description || "";
    if (!url || urlsProcessadas.has(url)) {
      continue;
    }
    const ehInutil = categoriasInuteis.includes(description) || url.includes("streetviewpixels");
    urlsProcessadas.add(url);
    // 3. Joga a foto na lista final
    rows.push({
      json: {
        id: idEstabelecimento,
        foto_index: i,
        description: description,
        url_original: url,
        eh_inutil: ehInutil
      }
    });
  }
}
// Retorna uma lista plana (1 item = 1 foto)
return rows;

// Mode: Run Once for All Items
const items = $input.all().map(i => i.json);

// Uma FOTO tem url_original. Uma RESPOSTA da IA tem o JSON com "resultado".
// Um mesmo item nunca é os dois ao mesmo tempo, então separamos com prioridade
// para a resposta: se parece resposta, é resposta; senão, se tem url, é foto.
function looksLikeResposta(i) {
  if (!i) return false;
  if (i.choices !== undefined) return true;
  if (i.message?.content !== undefined) return true;
  if (typeof i.content === 'string') return true;
  if (typeof i.resultado === 'string') return true;
  return false;
}

const respostasRaw = items.filter(i => looksLikeResposta(i));
const fotos = items.filter(i => !looksLikeResposta(i) && i.url_original !== undefined);

function parseResposta(aiOutput) {
  if (!aiOutput) return null;

  // 1) Extrai o texto bruto de onde quer que ele esteja
  let rawText = "";
  if (aiOutput.choices && aiOutput.choices[0] && aiOutput.choices[0].message) {
    rawText = aiOutput.choices[0].message.content;
  } else if (typeof aiOutput.content === 'string') {
    rawText = aiOutput.content;
  } else if (typeof aiOutput === 'string') {
    rawText = aiOutput;
  } else if (typeof aiOutput.resultado === 'string') {
    // caso o item já venha "achatado" com resultado/id/foto_index no topo
    rawText = JSON.stringify(aiOutput);
  }
  if (!rawText) return null;

  // 2) Tenta parsear o JSON da IA
  let parsedJson = null;
  try {
    let fixedText = rawText.trim();
    // tira cercas de markdown se a IA escapou e mandou ```json ... ```
    fixedText = fixedText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
    if (!fixedText.endsWith('}')) fixedText += '\n}';
    parsedJson = JSON.parse(fixedText);
  } catch (e) {
    parsedJson = null;
  }

  // 3) Se parseou, extrai pelos campos; senão cai no regex
  let id = null;
  let foto_index = null;
  let resultado = "";

  if (parsedJson) {
    id = parsedJson.id ?? null;
    foto_index = parsedJson.foto_index ?? null;
    resultado = parsedJson.resultado || "";
  } else {
    const idMatch = rawText.match(/"id"\s*:\s*"([^"]+)"/);
    const fiMatch = rawText.match(/"foto_index"\s*:\s*(\d+)/);
    const resMatch = rawText.match(/"resultado"\s*:\s*"([^"]*(?:\\.[^"]*)*)"/);
    id = idMatch ? idMatch[1] : null;
    foto_index = fiMatch ? parseInt(fiMatch[1], 10) : null;
    resultado = resMatch ? resMatch[1].replace(/\\"/g, '"') : "";
  }

  // normaliza foto_index para número inteiro quando possível
  if (foto_index !== null && foto_index !== undefined) {
    const fiNum = parseInt(foto_index, 10);
    foto_index = isNaN(fiNum) ? null : fiNum;
  }

  // 4) Separa nota e justificativa de "N.N: justificativa"
  let nota = null;
  let justificativa = null;
  if (resultado && resultado.trim() !== "") {
    const idx = resultado.indexOf(":");
    if (idx !== -1) {
      const notaNum = parseFloat(resultado.slice(0, idx).trim().replace(",", "."));
      nota = isNaN(notaNum) ? null : notaNum;
      justificativa = resultado.slice(idx + 1).trim();
    } else {
      justificativa = resultado.trim();
    }
  }

  return {
    id,
    foto_index,
    nota,
    justificativa,
    resposta_bruta: rawText,
  };
}

// Indexa as respostas por chave "id__foto_index".
// Se houver vários ids diferentes e/ou vários foto_index, cada par é único.
const respMap = new Map();
for (const r of respostasRaw) {
  const p = parseResposta(r);
  if (!p || p.id === null || p.foto_index === null) continue;
  const key = `${p.id}__${p.foto_index}`;
  // não sobrescreve uma resposta já casada (mantém a primeira válida)
  if (!respMap.has(key)) respMap.set(key, p);
}

// Casa cada foto com sua resposta pela chave id+foto_index (não por posição)
const rows = fotos.map((foto) => {
  const key = `${foto.id}__${foto.foto_index}`;
  const parsed = respMap.get(key) || { nota: null, justificativa: null, resposta_bruta: null };
  return {
    id: foto.id,
    foto_index_original: foto.foto_index, // guarda o original pra desempate
    description: foto.description,
    url_original: foto.url_original,
    eh_inutil: foto.eh_inutil,
    nota_capa: parsed.nota,
    justificativa_capa: parsed.justificativa,
    resposta_bruta: parsed.resposta_bruta,
    serve_como_capa: parsed.nota !== null && parsed.nota >= 7,
  };
});

// Agrupa por id: o ranking/reindex de foto_index é feito DENTRO de cada id,
// para funcionar quando o batch traz vários estabelecimentos misturados.
const porId = new Map();
for (const row of rows) {
  if (!porId.has(row.id)) porId.set(row.id, []);
  porId.get(row.id).push(row);
}

const out = [];
for (const grupo of porId.values()) {
  // Ordena por nota decrescente; empate: foto_index_original crescente
  grupo.sort((a, b) => {
    const na = a.nota_capa ?? -Infinity;
    const nb = b.nota_capa ?? -Infinity;
    if (nb !== na) return nb - na;
    return (a.foto_index_original ?? Infinity) - (b.foto_index_original ?? Infinity);
  });

  // Reatribui foto_index em ordem crescente conforme a posição pós-sort,
  // por estabelecimento (0 = melhor foto daquele id)
  grupo.forEach((row, i) => {
    out.push({
      json: {
        id: row.id,
        foto_index: i, // 0 = melhor foto deste id, 1 = segunda melhor, etc.
        description: row.description,
        url_original: row.url_original,
        eh_inutil: row.eh_inutil,
        nota_capa: row.nota_capa,
        justificativa_capa: row.justificativa_capa,
        resposta_bruta: row.resposta_bruta,
        serve_como_capa: row.serve_como_capa,
      }
    });
  });
}

return out;

// Mode: Run Once for All Items
// Adiciona campos de avaliação de capa em cada foto.
// Fotos marcadas como eh_inutil recebem valores padrão de rejeição automática.

const items = $input.all().map(i => i.json);

const rows = items.map(foto => {
  if (foto.eh_inutil) {
    return {
      json: {
        ...foto,
        nota_capa: 0,
        justificativa_capa: "Imagem do Google Street View (ou outras), inadequada como capa de perfil profissional.",
        resposta_bruta: "Imagem do Google Street View (ou outras), inadequada como capa de perfil profissional.",
        serve_como_capa: false,
      }
    };
  }

  // Foto útil: campos vazios, prontos para serem preenchidos pela IA depois
  return {
    json: {
      ...foto,
      nota_capa: null,
      justificativa_capa: null,
      resposta_bruta: null,
      serve_como_capa: null,
    }
  };
});

return rows;

const items = $input.all().map(i => i.json);

const fotosPorId = /** @type {Record<string, any[]>} */ ({});

for (const item of items) {
  if (item && item.id && item.foto_index !== undefined && !item.eh_inutil && item.nota_capa >= 6) {
    if (!fotosPorId[item.id]) {
      fotosPorId[item.id] = [];
    }
    fotosPorId[item.id].push(item);
  }
}

const resultados = Object.keys(fotosPorId).map(id => {
  const fotosDoEstabelecimento = fotosPorId[id];

  fotosDoEstabelecimento.sort((a, b) => a.foto_index - b.foto_index);

  return {
    json: {
      id: id,
      fotos_analise: fotosDoEstabelecimento
    }
  };
});

return resultados;

const inputItems = $input.all();
const previousItems = $('Switch').all();

const vistos = new Set();

return inputItems.map((item, index) => {
  const original = previousItems[index].json;

  // Erro de download/processamento → inútil
  if (item.json.error) {
    return {
      json: {
        ...original,        // url_original preservada
        eh_inutil: true
      }
    };
  }

  // Chave SÓ para comparação (não afeta o que sai no fluxo)
  const chaveComparacao = (original.url_original || '')
    .split('?')[0]
    .replace(/=s\d+-k-no$/, '')
    .replace(/=s\d+.*$/, '');

  const ehDuplicata = Boolean(chaveComparacao) && vistos.has(chaveComparacao);
  if (chaveComparacao && !ehDuplicata) {
    vistos.add(chaveComparacao);
  }

  return {
    json: {
      ...original,          // url_original sai exatamente como entrou
      eh_inutil: original.eh_inutil || ehDuplicata
    }
  };
});

// Lê o campo existente SEM alterá-lo, e adiciona um campo novo com frases numeradas.
const texto = $json.comentarios_formatados || "";

// 1) separa cada "Comentário N: ..." preservando o número original
const blocos = texto
  .split(/\n\s*\n/)            // comentários são separados por linha em branco
  .map(b => b.trim())
  .filter(Boolean);

const linhas = [];
let contadorFrase = 0;

for (const bloco of blocos) {
  // remove o rótulo "Comentário N:" do início, guardando o número
  const m = bloco.match(/^Coment[áa]rio\s+(\d+)\s*:\s*([\s\S]*)$/i);
  const numComentario = m ? m[1] : "?";
  const corpo = m ? m[2] : bloco;

  // 2) quebra o corpo em frases (fim de frase ou quebra de linha)
  const frases = corpo
    .split(/(?<=[.!?])\s+|\n+/)
    .map(f => f.trim())
    .filter(f => f.length > 0);

  // se o comentário não tiver pontuação, ele inteiro vira uma "frase"
  const lista = frases.length ? frases : [corpo.trim()].filter(Boolean);

  for (const f of lista) {
    contadorFrase++;
    // formato: "F12 (C10): frase isolada"
    linhas.push(`F${contadorFrase} (C${numComentario}): ${f}`);
  }
}

// adiciona o campo novo, mantém todo o resto do item intacto
$json.comentarios_frases = linhas.join("\n");

return $input.item;

// Limpa a saída dos agentes mas MANTÉM cada _review como STRING JSON,
// e MANTÉM os itens separados (é o que o Organizer espera receber).
// Só desembrulha {action,text} e normaliza, sem mudar a estrutura.

const CAMPOS = ["service_review", "price_to_value_review", "space_review", "capacity_review", "summary"];

function limpaParaString(valor) {
  if (valor == null) return valor;

  let obj = (typeof valor === "object") ? valor : null;
  if (obj === null && typeof valor === "string") {
    try { obj = JSON.parse(valor.trim()); } catch (e) { return valor; } // não parseou: devolve como veio
  }
  if (!obj) return valor;

  // desembrulha {action:"parse", text:"{...}"}
  if (obj.text && (obj.action || obj.resultado === undefined)) {
    try {
      const inner = JSON.parse(obj.text);
      if (inner && (inner.resultado !== undefined || inner.id !== undefined)) obj = inner;
    } catch (e) {}
  }

  // re-serializa como string JSON limpa { id, resultado }
  return JSON.stringify({
    id: obj.id ?? null,
    resultado: obj.resultado ?? null
  });
}

const out = [];
for (const item of $input.all()) {
  const novo = { ...item.json };
  for (const campo of CAMPOS) {
    if (novo[campo] !== undefined) {
      novo[campo] = limpaParaString(novo[campo]);
    }
  }
  out.push({ json: novo });
}
return out;
